from dataclasses import dataclass, field


@dataclass(slots=True)
class StrategyState:
    coverage: float = 0.0
    crashes: int = 0
    static_findings: int = 0


@dataclass(slots=True)
class ExploitStrategyPlanner:
    q_table: dict[tuple[int, int, int], dict[str, float]] = field(default_factory=dict)

    def recommend_strategy(self, static_data: dict, fuzz_data: dict) -> dict:
        state = StrategyState(
            coverage=float(fuzz_data.get("iterations", 0)) / max(float(fuzz_data.get("iterations", 1)), 1.0),
            crashes=int(fuzz_data.get("crash_count", 0)),
            static_findings=int(static_data.get("finding_count", 0)),
        )

        if state.crashes > 0:
            action = "replay-and-triage-crashes"
        elif state.static_findings > 0:
            action = "targeted-fuzzing-on-static-hotspots"
        else:
            action = "coverage-guided-exploration"

        return {
            "state": {
                "coverage": state.coverage,
                "crashes": state.crashes,
                "static_findings": state.static_findings,
            },
            "recommended_action": action,
            "reward_function": {
                "new_coverage": 1,
                "vulnerability_discovery": 10,
                "redundant_test_penalty": -1,
            },
            "summary": f"Planner recommends: {action}",
        }

